import React, { useState, useEffect, useCallback } from 'react';
import api from '../utils/api';

interface Message {
  id: string;
  canal: string;
  statut: string;
  sentAt: string;
  content?: string;
}

interface Lead {
  id: string;
  nom: string;
  email?: string;
  entreprise?: string;
  secteur?: string;
  score?: number;
  categorie?: string;
  statut: string;
  messages?: Message[];
}

interface Filters {
  search: string;
  categorie: string;
  statut: string;
  page: number;
}

const LIMIT = 20;

const CATEGORIE_DOT: Record<string, string> = {
  CHAUD: 'bg-red-400',
  TIEDE: 'bg-amber-400',
  FROID: 'bg-blue-400',
};

const CATEGORIE_TEXT: Record<string, string> = {
  CHAUD: 'text-red-400',
  TIEDE: 'text-amber-400',
  FROID: 'text-blue-400',
};

const STATUT_COLORS: Record<string, string> = {
  NOUVEAU: 'text-zinc-400',
  CONTACTE: 'text-amber-400',
  EN_COURS: 'text-indigo-400',
  CONVERTI: 'text-emerald-400',
  PERDU: 'text-red-400',
  BLACKLIST: 'text-zinc-600',
};

const CATEGORIES = ['CHAUD', 'TIEDE', 'FROID'];
const STATUTS = ['NOUVEAU', 'CONTACTE', 'EN_COURS', 'CONVERTI', 'PERDU', 'BLACKLIST'];

function ScoreBar({ score }: { score?: number }): React.ReactElement {
  const val = score ?? 0;
  const pct = (val / 10) * 100;
  const color = val >= 7 ? 'bg-emerald-400' : val >= 4 ? 'bg-amber-400' : 'bg-red-400';
  return (
    <div className="flex items-center gap-2">
      <div className="w-16 h-1.5 bg-zinc-800 rounded-full overflow-hidden">
        <div className={`h-full rounded-full ${color}`} style={{ width: `${pct}%` }} />
      </div>
      <span className="text-xs font-medium text-zinc-300 tabular-nums">{val}</span>
    </div>
  );
}

function SearchIcon(): React.ReactElement {
  return (
    <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
      <circle cx="11" cy="11" r="8" /><line x1="21" y1="21" x2="16.65" y2="16.65" />
    </svg>
  );
}

function ExportIcon(): React.ReactElement {
  return (
    <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
      <path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4" />
      <polyline points="7 10 12 15 17 10" />
      <line x1="12" y1="15" x2="12" y2="3" />
    </svg>
  );
}

export default function LeadsPage(): React.ReactElement {
  const [leads, setLeads] = useState<Lead[]>([]);
  const [total, setTotal] = useState<number>(0);
  const [filters, setFilters] = useState<Filters>({ search: '', categorie: '', statut: '', page: 1 });
  const [loading, setLoading] = useState<boolean>(false);

  const fetchLeads = useCallback(async () => {
    setLoading(true);
    try {
      const params: Record<string, any> = { ...filters, limit: LIMIT };
      Object.keys(params).forEach((k) => !params[k] && delete params[k]);
      const { data } = await api.get('/leads', { params });
      setLeads(data.leads);
      setTotal(data.total);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  }, [filters]);

  useEffect(() => {
    fetchLeads();
  }, [fetchLeads]);

  const deleteLead = async (id: string): Promise<void> => {
    if (!window.confirm('Supprimer ce lead ?')) return;
    await api.delete(`/leads/${id}`);
    fetchLeads();
  };

  const updateStatut = async (id: string, statut: string): Promise<void> => {
    await api.put(`/leads/${id}`, { statut });
    fetchLeads();
  };

  const from = (filters.page - 1) * LIMIT + 1;
  const to = Math.min(filters.page * LIMIT, total);

  return (
    <div className="flex flex-col h-full">
      {/* Top Bar */}
      <div className="px-6 py-5 border-b border-zinc-800 flex items-center justify-between">
        <div className="flex items-center gap-3">
          <h1 className="text-base font-semibold text-zinc-100">Leads</h1>
          <span className="px-2 py-0.5 rounded-md bg-zinc-800 text-zinc-400 text-xs font-medium tabular-nums">
            {total}
          </span>
        </div>
        <a
          href="http://localhost:3001/export?format=csv"
          className="flex items-center gap-1.5 px-3 py-1.5 bg-zinc-800 hover:bg-zinc-700 border border-zinc-700 text-zinc-300 text-xs font-medium rounded-md transition-colors"
        >
          <ExportIcon />
          Exporter CSV
        </a>
      </div>

      {/* Filter Row */}
      <div className="px-6 py-3 border-b border-zinc-800 flex items-center gap-3 flex-wrap">
        {/* Search */}
        <div className="relative">
          <span className="absolute left-2.5 top-1/2 -translate-y-1/2 text-zinc-500">
            <SearchIcon />
          </span>
          <input
            className="pl-8 pr-3 py-1.5 bg-zinc-900 border border-zinc-800 rounded-md text-xs text-zinc-200 placeholder-zinc-600 focus:outline-none focus:border-zinc-600 w-56 transition-colors"
            placeholder="Rechercher un lead..."
            value={filters.search}
            onChange={(e) => setFilters({ ...filters, search: e.target.value, page: 1 })}
          />
        </div>

        {/* Category pills */}
        <div className="flex items-center gap-1.5">
          <button
            onClick={() => setFilters({ ...filters, categorie: '', page: 1 })}
            className={`px-2.5 py-1 rounded-md text-xs font-medium transition-colors ${
              filters.categorie === ''
                ? 'bg-zinc-700 text-zinc-100'
                : 'text-zinc-500 hover:text-zinc-300 hover:bg-zinc-800'
            }`}
          >
            Tous
          </button>
          {CATEGORIES.map((c) => (
            <button
              key={c}
              onClick={() => setFilters({ ...filters, categorie: filters.categorie === c ? '' : c, page: 1 })}
              className={`flex items-center gap-1.5 px-2.5 py-1 rounded-md text-xs font-medium transition-colors ${
                filters.categorie === c
                  ? 'bg-zinc-700 text-zinc-100'
                  : 'text-zinc-500 hover:text-zinc-300 hover:bg-zinc-800'
              }`}
            >
              <span className={`w-1.5 h-1.5 rounded-full ${CATEGORIE_DOT[c]}`} />
              {c.charAt(0) + c.slice(1).toLowerCase()}
            </button>
          ))}
        </div>

        {/* Status dropdown */}
        <select
          className="ml-auto px-2.5 py-1.5 bg-zinc-900 border border-zinc-800 rounded-md text-xs text-zinc-400 focus:outline-none focus:border-zinc-600 transition-colors"
          value={filters.statut}
          onChange={(e) => setFilters({ ...filters, statut: e.target.value, page: 1 })}
        >
          <option value="">Tous les statuts</option>
          {STATUTS.map((s) => (
            <option key={s} value={s}>{s}</option>
          ))}
        </select>
      </div>

      {/* Table */}
      <div className="flex-1 overflow-auto">
        <table className="w-full text-xs">
          <thead className="sticky top-0 bg-zinc-950 border-b border-zinc-800">
            <tr>
              {['Nom', 'Email', 'Entreprise', 'Secteur', 'Score', 'Catégorie', 'Statut', ''].map((h) => (
                <th key={h} className="px-5 py-3 text-left text-zinc-500 font-medium uppercase tracking-wider text-[10px]">
                  {h}
                </th>
              ))}
            </tr>
          </thead>
          <tbody className="divide-y divide-zinc-800/60">
            {loading ? (
              <tr>
                <td colSpan={8} className="text-center py-16 text-zinc-600">
                  <div className="flex flex-col items-center gap-2">
                    <svg className="animate-spin w-5 h-5 text-zinc-700" viewBox="0 0 24 24" fill="none">
                      <circle cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="2" strokeDasharray="40" strokeDashoffset="10" />
                    </svg>
                    <span>Chargement...</span>
                  </div>
                </td>
              </tr>
            ) : leads.length === 0 ? (
              <tr>
                <td colSpan={8} className="text-center py-16 text-zinc-600">
                  <div className="flex flex-col items-center gap-2">
                    <svg width="32" height="32" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.25" strokeLinecap="round" strokeLinejoin="round" className="text-zinc-800">
                      <path d="M17 21v-2a4 4 0 0 0-4-4H5a4 4 0 0 0-4 4v2" />
                      <circle cx="9" cy="7" r="4" />
                      <path d="M23 21v-2a4 4 0 0 0-3-3.87" />
                      <path d="M16 3.13a4 4 0 0 1 0 7.75" />
                    </svg>
                    <p className="text-zinc-500 text-xs">Aucun lead trouvé</p>
                  </div>
                </td>
              </tr>
            ) : (
              leads.map((lead) => (
                <tr key={lead.id} className="hover:bg-zinc-900/50 transition-colors group">
                  <td className="px-5 py-3 font-medium text-zinc-200">{lead.nom}</td>
                  <td className="px-5 py-3 text-zinc-500">{lead.email || '—'}</td>
                  <td className="px-5 py-3 text-zinc-500">{lead.entreprise || '—'}</td>
                  <td className="px-5 py-3 text-zinc-500">{lead.secteur || '—'}</td>
                  <td className="px-5 py-3">
                    <ScoreBar score={lead.score} />
                  </td>
                  <td className="px-5 py-3">
                    {lead.categorie ? (
                      <span className={`flex items-center gap-1.5 ${CATEGORIE_TEXT[lead.categorie] || 'text-zinc-400'}`}>
                        <span className={`w-1.5 h-1.5 rounded-full ${CATEGORIE_DOT[lead.categorie] || 'bg-zinc-600'}`} />
                        {lead.categorie.charAt(0) + lead.categorie.slice(1).toLowerCase()}
                      </span>
                    ) : (
                      <span className="text-zinc-600">—</span>
                    )}
                  </td>
                  <td className="px-5 py-3">
                    <select
                      className={`bg-transparent border-none outline-none text-xs font-medium cursor-pointer ${
                        STATUT_COLORS[lead.statut] || 'text-zinc-400'
                      }`}
                      value={lead.statut}
                      onChange={(e) => updateStatut(lead.id, e.target.value)}
                    >
                      {STATUTS.map((s) => (
                        <option key={s} value={s} className="bg-zinc-900 text-zinc-200">
                          {s}
                        </option>
                      ))}
                    </select>
                  </td>
                  <td className="px-5 py-3">
                    <button
                      onClick={() => deleteLead(lead.id)}
                      className="opacity-0 group-hover:opacity-100 text-zinc-600 hover:text-red-400 transition-all text-xs"
                    >
                      Supprimer
                    </button>
                  </td>
                </tr>
              ))
            )}
          </tbody>
        </table>
      </div>

      {/* Pagination */}
      {total > 0 && (
        <div className="px-6 py-3 border-t border-zinc-800 flex items-center justify-between">
          <span className="text-xs text-zinc-500 tabular-nums">
            {from}–{to} sur {total}
          </span>
          <div className="flex items-center gap-1.5">
            <button
              disabled={filters.page <= 1}
              onClick={() => setFilters({ ...filters, page: filters.page - 1 })}
              className="px-3 py-1.5 bg-zinc-900 border border-zinc-800 rounded-md text-xs text-zinc-400 hover:text-zinc-200 hover:border-zinc-700 disabled:opacity-30 disabled:cursor-not-allowed transition-colors"
            >
              ← Précédent
            </button>
            <span className="px-2 py-1.5 text-xs text-zinc-500 tabular-nums">
              Page {filters.page}
            </span>
            <button
              disabled={filters.page * LIMIT >= total}
              onClick={() => setFilters({ ...filters, page: filters.page + 1 })}
              className="px-3 py-1.5 bg-zinc-900 border border-zinc-800 rounded-md text-xs text-zinc-400 hover:text-zinc-200 hover:border-zinc-700 disabled:opacity-30 disabled:cursor-not-allowed transition-colors"
            >
              Suivant →
            </button>
          </div>
        </div>
      )}
    </div>
  );
}
